        assertTrue(format1.equals(format2));

        format2 = new CSVFormat(CSVFormat.COMMA, CSVFormat.DOUBLE_QUOTE_CHAR, null, null, null, false, true, CSVFormat.CRLF,
                null, null, null, false, false, false, false, false);
        assertTrue(format1.equals(format2));
    }
}
